sql:
SELECT SUM(usage_count) AS total_usage
FROM park_usage
WHERE activity_id = 1 AND usage_date = '2023-05-01';

SELECT AVG(usage_count) AS average_usage
FROM park_usage
WHERE park_id = 1 AND facility_id = 1 AND usage_date = '2023-05-01';

SELECT COUNT(*) AS total_reports
  FROM citizen_reports
  WHERE park_id = 1 AND report_date = '2023-05-01';

SELECT activity_name
FROM outdoor_activities
WHERE recommended_weather = 'Sunny';

SELECT report_text, rating
FROM citizen_reports
WHERE rating > 3;

external_knowledge:
- "Most popular" refers to the activities with the highest total usage counts and average ratings; 
- "Weather conditions" include outlook, temperature, humidity, and wind; 
- Activities are considered under various combinations of these conditions to understand their impact on usage and ratings.

